document.querySelectorAll(".add-barcode").forEach((function(add){addBarcode(add)}));document.querySelectorAll(".delete-barcode").forEach((function(del){deleteBarcode(del)}));function addBarcode(element){element.addEventListener("click",(function(event){const collection_id=this.dataset.idCollection;const collection_index=this.dataset.indexCollection;const collection_current=document.querySelector(`[data-id="${collection_id}"]`);const collection_elements=collection_current.querySelectorAll(`[data-collection="${collection_id}"]`);if(collection_elements.length>=5){let dangerToast='{ "type":"danger" , '+'"header":"Ошибка при изменении продукта"  , '+`"message" : "Превышено максимальное количество элементов" }`;createToast(JSON.parse(dangerToast));return}const prototype=document.querySelector(`[data-prototype-collection="${collection_id}"]`);let prototype_content=prototype.innerText;const prototype_name=prototype.dataset.prototypeName;const regex=new RegExp(prototype_name,"g");prototype_content=prototype_content.replace(regex,collection_index);const template=document.createElement("template");prototype_content=prototype_content.replace(/value="[^"]*"/g,'value=""');template.innerHTML=prototype_content.trim();const fragment=template.content.cloneNode(true);collection_current.appendChild(fragment);this.dataset.indexCollection=parseInt(collection_index)+1;const last_add=collection_elements[collection_elements.length-1];const last_del=last_add.querySelector("."+"delete-barcode");deleteBarcode(last_del)}))}function deleteBarcode(element){element.addEventListener("click",(function(event){const collection_id=this.dataset.idCollection;const element_id=this.dataset.idBarcode;const collection_current=document.querySelector(`[data-id="${collection_id}"]`);const collection_elements=collection_current.querySelectorAll(`[data-collection="${collection_id}"]`);let collection_element=collection_current.querySelector(`[data-id="${element_id}"]`);if(collection_element){if(collection_elements.length===1){let dangerToast='{ "type":"danger" , '+'"header":"Ошибка при изменении продукта"  , '+`"message" : "Достигнуто минимальное количество элементов" }`;createToast(JSON.parse(dangerToast));return}collection_element.remove()}}))}